class MinHeap {
    constructor() { this.data = []; }
    get size() { return this.data.length; }
    peek() { return this.data[0]; }
    push(item) {
        this.data.push(item);
        let i = this.data.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this.data[p][0] <= this.data[i][0]) break;
            [this.data[p], this.data[i]] = [this.data[i], this.data[p]];
            i = p;
        }
    }
    pop() {
        const top = this.data[0];
        const last = this.data.pop();
        if (this.data.length > 0) {
            this.data[0] = last;
            let i = 0;
            const n = this.data.length;
            while (true) {
                let l = i * 2 + 1, r = i * 2 + 2, smallest = i;
                if (l < n && this.data[l][0] < this.data[smallest][0]) smallest = l;
                if (r < n && this.data[r][0] < this.data[smallest][0]) smallest = r;
                if (smallest === i) break;
                [this.data[i], this.data[smallest]] = [this.data[smallest], this.data[i]];
                i = smallest;
            }
        }
        return top;
    }
}

class StockPrice {
    constructor() {
        this.prices = new Map();
        this.minHeap = new MinHeap();
        this.maxHeap = new MinHeap();
        this.latestTs = 0;
    }

    update(timestamp, price) {
        this.prices.set(timestamp, price);
        if (timestamp > this.latestTs) this.latestTs = timestamp;
        this.minHeap.push([price, timestamp]);
        this.maxHeap.push([-price, timestamp]);
    }

    current() {
        return this.prices.get(this.latestTs);
    }

    maximum() {
        while (true) {
            const [negPrice, ts] = this.maxHeap.peek();
            if (this.prices.get(ts) === -negPrice) return -negPrice;
            this.maxHeap.pop();
        }
    }

    minimum() {
        while (true) {
            const [price, ts] = this.minHeap.peek();
            if (this.prices.get(ts) === price) return price;
            this.minHeap.pop();
        }
    }
}
